module traffic_light(
    input rst_n,
    input clk,
    input pass_request,
    output reg red,
    output reg yellow,
    output reg green
);

localparam GREEN_TIME = 60;
localparam YELLOW_TIME = 5;
localparam RED_TIME = 10;

reg [5:0] timer;
reg [1:0] state;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        timer <= 0;
        state <= 0;
        red <= 0;
        yellow <= 0;
        green <= 1;
    end else begin
        case (state)
            0: begin // Green state
                if (timer == GREEN_TIME - 1) begin
                    state <= 1; // Transition to yellow
                    timer <= 0;
                end else begin
                    timer <= timer + 1;
                end
                red <= 0;
                yellow <= 0;
                green <= 1;
            end
            1: begin // Yellow state
                if (timer == YELLOW_TIME - 1) begin
                    state <= 2; // Transition to red
                    timer <= 0;
                end else begin
                    timer <= timer + 1;
                end
                red <= 0;
                yellow <= 1;
                green <= 0;
            end
            2: begin // Red state
                if (timer == RED_TIME - 1) begin
                    state <= 0; // Transition to green
                    timer <= 0;
                end else begin
                    timer <= timer + 1;
                end
                red <= 1;
                yellow <= 0;
                green <= 0;
            end
        endcase

        if (pass_request && timer > 10) begin
            state <= 0; // Prioritize pedestrian
            timer <= 0;
        end
    end
end

endmodule
